const WeatherCard = ({ city, icon, temperature, wind, humidity }) => {
  return (
    <div>
      <h2>{city}</h2>
      <img src={icon} alt="weather icon" />
      <p>{temperature}</p>
      <p>{wind}</p>
      <p>{humidity}</p>
    </div>
  );
};

export default WeatherCard;
